class DirectoryEntry:
    def __init__(self, name, inode, entry_type):
        self.name = name
        self.inode = inode
        self.type = entry_type  # 'file' or 'directory'

class Directory:
    def __init__(self):
        self.entries = []

    def search_linear(self, filename):
        """Linear search O(n) - simple but slow"""
        for entry in self.entries:
            if entry.name == filename:
                return entry
        return None

    def search_hash(self, filename, hash_table):
        """Hash-based search O(1) average"""
        index = hash(filename) % len(hash_table)
        bucket = hash_table[index]
        for entry in bucket:
            if entry.name == filename:
                return entry
        return None

    def add_entry(self, entry):
        self.entries.append(entry)

# Example usage
directory = Directory()
directory.add_entry(DirectoryEntry("file1.txt", 1001, "file"))
directory.add_entry(DirectoryEntry("docs", 2001, "directory"))
result = directory.search_linear("file1.txt")
print(f"Found: {result.name if result else 'Not found'}")

#include <stdio.h>
#include <string.h>

typedef struct DirEntry {
    char name[256];
    int inode;
    struct DirEntry* parent;
    struct DirEntry* children[100];
    int childCount;
} DirEntry;

// Current working directory (global)
DirEntry* currentDir;

// Resolve relative path
DirEntry* resolvePath(char* path) {
    DirEntry* target = currentDir;

    if (path[0] == '/') {
        // Absolute path: start from root
        target = findRoot();
        path++; // skip leading '/'
    }

    char* token = strtok(path, "/");
    while (token != NULL) {
        if (strcmp(token, ".") == 0) {
            // Current directory - no change
        } else if (strcmp(token, "..") == 0) {
            // Parent directory
            if (target->parent != NULL) {
                target = target->parent;
            }
        } else {
            // Find child directory
            DirEntry* found = NULL;
            for (int i = 0; i < target->childCount; i++) {
                if (strcmp(target->children[i]->name, token) == 0) {
                    found = target->children[i];
                    break;
                }
            }
            if (found == NULL) return NULL; // Not found
            target = found;
        }
        token = strtok(NULL, "/");
    }
    return target;
}

int main() {
    // Example: resolve "./docs/../notes.txt"
    char path[] = "./docs/../notes.txt";
    DirEntry* result = resolvePath(path);
    return 0;
}

import java.util.*;

enum Permission {
    READ,    // List directory contents
    WRITE,   // Create/delete entries
    EXECUTE  // Access and traverse
}

enum UserType {
    OWNER, GROUP, OTHERS
}

class AccessControl {
    private Map<String, Map<UserType, Set<Permission>>> acl;

    public AccessControl() {
        this.acl = new HashMap<>();
    }

    // Check if user has required permission
    public boolean hasPermission(String username, String group, 
                                  String dirName, Permission required) {

        // Get user's effective permissions
        Set<Permission> perms = getEffectivePermissions(
            username, group, dirName
        );

        return perms.contains(required);
    }

    private Set<Permission> getEffectivePermissions(
            String username, String group, String dirName) {

        Set<Permission> effective = new HashSet<>();
        AccessInfo info = getAccessInfo(username, group);

        // Check owner permissions first
        if (info.isOwner) {
            effective.addAll(acl.get(dirName).get(UserType.OWNER));
        }
        // Then group permissions
        else if (info.isInGroup) {
            effective.addAll(acl.get(dirName).get(UserType.GROUP));
        }
        // Finally others
        else {
            effective.addAll(acl.get(dirName).get(UserType.OTHERS));
        }

        return effective;
    }

    // Set permissions for directory
    public void setPermissions(String dirName, UserType userType, 
                               Set<Permission> permissions) {
        acl.computeIfAbsent(dirName, k -> new HashMap<>());
        acl.get(dirName).put(userType, permissions);
    }

    private AccessInfo getAccessInfo(String username, String group) {
        // Implementation would check system user database
        return new AccessInfo();
    }

    private static class AccessInfo {
        boolean isOwner;
        boolean isInGroup;
    }
}

public class DirectoryProtection {
    public static void main(String[] args) {
        AccessControl ac = new AccessControl();

        // Set up directory permissions
        Set<Permission> ownerPerms = new HashSet<>(Arrays.asList(
            Permission.READ, Permission.WRITE, Permission.EXECUTE
        ));
        Set<Permission> groupPerms = new HashSet<>(Arrays.asList(
            Permission.READ, Permission.EXECUTE
        ));
        Set<Permission> otherPerms = new HashSet<>(Arrays.asList(
            Permission.READ
        ));

        ac.setPermissions("/home/docs", UserType.OWNER, ownerPerms);
        ac.setPermissions("/home/docs", UserType.GROUP, groupPerms);
        ac.setPermissions("/home/docs", UserType.OTHERS, otherPerms);

        // Check permissions
        boolean canWrite = ac.hasPermission("john", "users", 
                                              "/home/docs", 
                                              Permission.WRITE);
        System.out.println("Can write: " + canWrite);
    }
}
